query getCountries($where1: CountryFilterInput, $where2: CountryFilterInput) {
  countriesContains: countries(where: $where1) {
    id
    nameEn
    nameRu
    isoCode
    alpha2
    __typename
  }
  countriesStartsWith: countries(where: $where2) {
    id
    nameEn
    nameRu
    isoCode
    alpha2
    __typename
  }
}

query getCities($where1: CityFilterInput, $where2: CityFilterInput) {
